import{_ as e,o as l,c as a,a2 as r}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"🫘 黃豆追蹤日誌 — 2026-05-01（週五）","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/2026-05-01.md","filePath":"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/2026-05-01.md"}'),i={name:"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/2026-05-01.md"};function n(s,t,o,d,g,h){return l(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="🫘-黃豆追蹤日誌-—-2026-05-01-週五" tabindex="-1">🫘 黃豆追蹤日誌 — 2026-05-01（週五） <a class="header-anchor" href="#🫘-黃豆追蹤日誌-—-2026-05-01-週五" aria-label="Permalink to &quot;🫘 黃豆追蹤日誌 — 2026-05-01（週五）&quot;">​</a></h1><blockquote><p>掃描時間：凌晨 5:00 Cron 自動觸發 資料來源：web_search (Google Search grounding)</p></blockquote><hr><h2 id="📋-8-項追蹤指標檢查結果" tabindex="-1">📋 8 項追蹤指標檢查結果 <a class="header-anchor" href="#📋-8-項追蹤指標檢查結果" aria-label="Permalink to &quot;📋 8 項追蹤指標檢查結果&quot;">​</a></h2><h3 id="✅-指標-1-usda-種植進度報告" tabindex="-1">✅ 指標 1：USDA 種植進度報告 <a class="header-anchor" href="#✅-指標-1-usda-種植進度報告" aria-label="Permalink to &quot;✅ 指標 1：USDA 種植進度報告&quot;">​</a></h3><p><strong>狀態：有變化 ⚠️（維持快速超前）</strong></p><ul><li>截至 4/26：黃豆已種植 <strong>23%</strong>，較五年平均（12%）快 <strong>11 個百分點</strong></li><li>印第安納州 35%（五年平均 +27）、伊利諾州 36%</li><li>玉米 25%（五年平均 19%），玉米出苗 7%（五年平均 4%）</li><li>種植進度大幅超前，但高肥料成本可能影響後續施肥與產量</li><li>📌 下一份 USDA 報告預計 5/5（週一）公布</li></ul><h3 id="✅-指標-2-巴西供應-收割-出口-豐收" tabindex="-1">✅ 指標 2：巴西供應（收割 + 出口 + 豐收） <a class="header-anchor" href="#✅-指標-2-巴西供應-收割-出口-豐收" aria-label="Permalink to &quot;✅ 指標 2：巴西供應（收割 + 出口 + 豐收）&quot;">​</a></h3><p><strong>狀態：無重大變化</strong></p><ul><li>2025/26 賽季巴西黃豆產量 <strong>1.778-1.79 億噸</strong>（創紀錄）</li><li>4 月巴西出口預估 <strong>1,587-1,640 萬噸</strong>（ANEC）</li><li>豐收導致全球價格承壓，巴西出口收入反而可能減少</li><li>📌 與昨日（4/30）相比無新變化</li></ul><h3 id="✅-指標-3-尿素價格-多單訊號" tabindex="-1">✅ 指標 3：尿素價格 + 多單訊號 <a class="header-anchor" href="#✅-指標-3-尿素價格-多單訊號" aria-label="Permalink to &quot;✅ 指標 3：尿素價格 + 多單訊號&quot;">​</a></h3><p><strong>狀態：有變化 🔴 價格回落但仍高檔</strong></p><ul><li>4/29 尿素基準價 <strong>$684.75/噸</strong>（較 4/29 $866/噸回落）</li><li>4 月第 3 週均價 $866/噸 → 4/29 基準價 $684.75（修正約 21%）</li><li>但 5 月尿素期貨（UFVK26）仍在 $625/噸</li><li>World Bank 預測 2026 年肥料價格上漲超過 30%</li><li>🚨 多單訊號仍有效（價格仍遠高於歷史水平）</li></ul><h3 id="✅-指標-4-荷莫茲海峽通航狀態" tabindex="-1">✅ 指標 4：荷莫茲海峽通航狀態 <a class="header-anchor" href="#✅-指標-4-荷莫茲海峽通航狀態" aria-label="Permalink to &quot;✅ 指標 4：荷莫茲海峽通航狀態&quot;">​</a></h3><p><strong>狀態：持續封閉 🔴 重大風險（深化）</strong></p><ul><li>商業船運實質停止，波斯灣滯留約 <strong>2,000 艘船</strong></li><li>即使海峽重開，恢復正常水平需 <strong>數個月</strong>（含排雷）</li><li>美國主導「Maritime Freedom Construct」（MFC）國際聯盟</li><li>法國和英國僅願意在衝突結束後協助</li><li>伊朗警告「前所未見軍事行動」</li><li>🚨 全球約 20% 石油和 LNG 流量受影響</li></ul><h3 id="✅-指標-5-中美貿易-中國進口" tabindex="-1">✅ 指標 5：中美貿易 + 中國進口 <a class="header-anchor" href="#✅-指標-5-中美貿易-中國進口" aria-label="Permalink to &quot;✅ 指標 5：中美貿易 + 中國進口&quot;">​</a></h3><p><strong>狀態：有變化 🟡 關稅退款啟動 + 新關稅替代</strong></p><ul><li>IEEPA 關稅退款首批 $1,660 億預計 <strong>5/11 開始</strong>（最高法院判決非法）</li><li>Trump Section 122 全球關稅 10%（至 7/24 到期）</li><li>USTR 對 60 個經濟體舉行 Section 301 聽證會</li><li>中國 25 Mt 黃豆採購承諾在目前市場條件下 <strong>不太可能實現</strong></li><li>中國 5/1 起對非洲 53 國零關稅（尋求替代貿易夥伴）</li></ul><h3 id="✅-指標-6-天然氣價格" tabindex="-1">✅ 指標 6：天然氣價格 <a class="header-anchor" href="#✅-指標-6-天然氣價格" aria-label="Permalink to &quot;✅ 指標 6：天然氣價格&quot;">​</a></h3><p><strong>狀態：有變化 🟢 小幅回升但仍低檔</strong></p><ul><li>4/30 天然氣小幅回升至 <strong>$2.65/MMBtu</strong>（前日 $2.64）</li><li>5 月 NYMEX 期貨（NGK26）收盤 $2.647</li><li>高庫存 + 暖冬導致價格持續承壓</li><li>Kalshi 預測 5/1 收盤 71% 機率 &gt; $2.599，15% 機率 &gt; $2.699</li><li>📉 天然氣仍處低檔 → 尿素成本壓力部分緩解</li></ul><h3 id="✅-指標-7-聖嬰-拉尼娜氣候風險" tabindex="-1">✅ 指標 7：聖嬰/拉尼娜氣候風險 <a class="header-anchor" href="#✅-指標-7-聖嬰-拉尼娜氣候風險" aria-label="Permalink to &quot;✅ 指標 7：聖嬰/拉尼娜氣候風險&quot;">​</a></h3><p><strong>狀態：無重大變化</strong></p><ul><li>La Niña 減弱，目前 ENSO 中性</li><li>聖嬰可能於 5-7 月出現（機率 61%-62%）</li><li>📌 與昨日相比無新變化，需持續監控</li></ul><h3 id="✅-指標-8-cbot-價格區間" tabindex="-1">✅ 指標 8：CBOT 價格區間 <a class="header-anchor" href="#✅-指標-8-cbot-價格區間" aria-label="Permalink to &quot;✅ 指標 8：CBOT 價格區間&quot;">​</a></h3><p><strong>狀態：有變化 🟡 小幅波動</strong></p><ul><li>CBOT 黃豆最活躍合約 4/30 約 <strong>$11.83/蒲式耳</strong>（1,183.27 美分）</li><li>日內波動：一度跌至 $11.90（-0.6%），尾盤回升至 +0.09%</li><li>5 月合約（ZSK26）4/29 收盤 <strong>$11.82¼</strong></li><li>目前仍介於 <strong>1,150-1,200</strong> 之間，<strong>未觸發任一邊界</strong></li><li>油價波動、中東戰事持續影響黃豆期貨走勢</li></ul><hr><h2 id="📊-綜合評估" tabindex="-1">📊 綜合評估 <a class="header-anchor" href="#📊-綜合評估" aria-label="Permalink to &quot;📊 綜合評估&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">#</th><th style="text-align:left;">指標</th><th style="text-align:center;">狀態</th><th style="text-align:center;">影響方向</th></tr></thead><tbody><tr><td style="text-align:center;">1</td><td style="text-align:left;">USDA 種植進度</td><td style="text-align:center;">⚠️ 快速超前（23% vs 5年均 12%）</td><td style="text-align:center;">利多（產量可能增加）</td></tr><tr><td style="text-align:center;">2</td><td style="text-align:left;">巴西供應/出口</td><td style="text-align:center;">無重大變化（創紀錄豐收）</td><td style="text-align:center;">利空（供應充足）</td></tr><tr><td style="text-align:center;">3</td><td style="text-align:left;">尿素價格 + 多單</td><td style="text-align:center;">🔴 回落至 $684 但仍高檔</td><td style="text-align:center;">利空（種植成本仍高）</td></tr><tr><td style="text-align:center;">4</td><td style="text-align:left;">荷莫茲海峽</td><td style="text-align:center;">🔴 持續封閉（2,000 艘滯留）</td><td style="text-align:center;">利空（供應鏈中斷）</td></tr><tr><td style="text-align:center;">5</td><td style="text-align:left;">中美貿易 + 進口</td><td style="text-align:center;">🟡 關稅退款啟動 + 新關稅替代</td><td style="text-align:center;">中性偏多</td></tr><tr><td style="text-align:center;">6</td><td style="text-align:left;">天然氣價格</td><td style="text-align:center;">🟢 小幅回升 $2.65（仍低檔）</td><td style="text-align:center;">利多（成本壓力緩解）</td></tr><tr><td style="text-align:center;">7</td><td style="text-align:left;">聖嬰/拉尼娜</td><td style="text-align:center;">無重大變化（ENSO 中性）</td><td style="text-align:center;">不確定</td></tr><tr><td style="text-align:center;">8</td><td style="text-align:left;">CBOT 價格區間</td><td style="text-align:center;">🟡 1,183 美分（未觸發邊界）</td><td style="text-align:center;">中性</td></tr></tbody></table><p><strong>多空平衡：偏空（荷莫茲深化 + 巴西豐收 vs 天然氣低檔 + 關稅部分改善）</strong></p><hr><p><em>報告產出：Dr.32 知識管家 | 模型：local/Qwen3.6-35B-A3B-4bit</em></p>',34)])])}const x=e(i,[["render",n]]);export{u as __pageData,x as default};
